INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('cpa-moex-00585', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '臺東公司於20X1年1月2日發行股票8,000股，面額$20，每股售價$22。該公司核定股數為20,000 股。公司今年發生下列庫藏股票交易事項：2月21日購回庫藏股票200股，每股購價$23；3月 15日出售庫藏股票200股，每股售價$25；5月28日購回庫藏股票200股，每股購價$25；6月4日 出售庫藏股票200股，每股售價$24；9月12日購回庫藏股票200股，每股售價$27。則該20X1年 底庫藏股票及由庫藏股票交易產生之資本公積餘額各為多少？', '["$4,600，$100", "$4,600，$200", "$5,400，$200", "$5,400，$400"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00586', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列有關權益交割股份基礎給付交易衡量日之敘述，何者正確？', '["衡量日在給與日之後", "衡量日即為給與日", "與非員工交易之衡量日為企業取得商品或對方提供勞務之日，與員工交易之衡量日為給與日", "與非員工交易之衡量日為給與日，與員工交易之衡量日為企業取得商品或對方提供勞務之日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00587', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '高雄公司宣告以土地作為財產股息發放，相關資料如下： 公允價值 宣告日 20X1/4/20 $400,000 除息日 20X1/5/2 $350,000 發放日 20X1/5/20 $380,000 該土地在高雄公司的帳面價值為$250,000，則高雄公司在20X1年，對土地之處分應認列多少 利益？', '["$0", "$100,000", "$130,000", "$150,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00588', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列有關企業發行金融工具之敘述，何者錯誤？', '["金融工具為權益工具的關鍵特性為發行人可無條件避免（拒絕）：㉑支付現金或其他金融資 產給另一方，或㉒按潛在不利於發行人之條件與另一方交換金融資產或金融負債之合約義務", "發行人若發行可贖回的特別股，企業有盈餘時必須發放特別股股利，此特別股分類為金融 負債", "發行人若發行有到期日且須強制贖回的特別股，此特別股分類為金融負債", "發行人若發行之特別股若依經濟實質分類為負債，但其在法律形式上仍為權益，故該特別 股股利係屬於盈餘分配"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00589', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '和平公司20X1年期末權益項目餘額為股本$10,000,000、保留盈餘$250,000、庫藏股$100,000。 20X2年度淨利$125,000，且20X2年曾發生過下列交易：⑴宣告並發放股票股利$40,000；⑵出 售設備損失$10,000；⑶認列商譽之減損$10,000；⑷於20X2年1月1日更正20X1年初之帳務錯 誤事項，當時對購入耐用年限3年之設備$30,000（採直線法折舊，殘值為0）卻以費用入帳； ⑸全數出售庫藏股票獲得現金$90,000。則該公司20X2年底保留盈餘之正確餘額為多少？', '["$355,000", "$345,000", "$335,000", "$325,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00590', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '於計算每股盈餘時，若去年約定之或有發行股份之所有條件恰好於今年期末均已全部達成， 則下列敘述何者正確？', '["計算當年度基本每股盈餘時，或有發行應增加之普通股數為零", "計算當年度稀釋每股盈餘時，或有發行應增加之普通股數視為期初已發行", "僅", "正確"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00591', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年1月1日出租設備給乙公司，租約規定租期三年，第一年租金$1,000,000，以後 每年調漲$100,000，為取得此一租約甲公司並支付仲介佣金$120,000。甲公司取得設備之成本 為$5,000,000，採直線法提折舊，預期耐用年限10年，沒有殘值。在不考慮所得稅的情況下， 試問甲公司20X1年與該設備有關（含營業租賃）之損益為何？', '["增加淨利$380,000", "增加淨利$460,000", "增加淨利$480,000", "增加淨利$560,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00592', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列租賃相關之名詞定義，何者正確？', '["不可取消之租賃，代表該租賃絕對不可取消", "租賃開始日係指承租人有權行使租賃資產使用權之日期", "對承租人與出租人而言，計入租賃給付之殘值保證的金額均相同", "未賺得融資收益係指租賃投資總額與租賃投資淨額之差"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00593', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '某一經濟現象有四種不同的會計處理方法，各會計處理方法與品質特性的關係如下表： 甲方法 乙方法 丙方法 丁方法 攸關性 有 有 有 無 可比性 有 有 有 有 可驗證性 有 無 無 有 及時性 有 無 無 有 忠實表述 無 有 有 有 可瞭解性 有 無 有 有 則那一種會計處理方法可以編製出最有用的會計資訊？', '["甲方法", "乙方法", "丙方法", "丁方法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00594', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於X5年1月1日取得乙公司100%股權，此一企業合併交易，產生廉價購買利益$500,000。 依稅法規定，廉價購買利益係自取得年度起分5年，每年以$100,000計入課稅所得。甲公司X5 年稅前淨利為$5,000,000，所得稅率為20%，假設無其他暫時性差異存在，所有可減除暫時性 差異在未來很有可能有課稅所得可供此差異使用，則甲公司X5年所得稅費用及X5年底資產 負債表應列報遞延所得稅資產或負債分別為：', '["$920,000及$0", "$1,000,000及$0", "$1,000,000及遞延所得稅資產$20,000", "$1,000,000及遞延所得稅負債$80,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00595', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司的新部門銷售A商品在20X1年為公司帶來銷貨收入$556,000，銷貨成本為$472,600。 甲公司在20X2年初查覺此新部門20X1年之營收認列方式錯誤，其 A 商品交易僅為其他公司 安排商品銷售予客戶屬於代理性質。此外，該部門以寄銷方式委託乙公司代售B商品，在20X1 年底將商品運送達乙公司時即認列銷貨收入$750,000及銷貨成本$637,000。不考慮所得稅影 響，上述錯誤將影響20X1年底之保留盈餘？', '["高估$113,000", "高估$29,600", "高估$196,400", "低估$83,400"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00596', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司X1年度的平均總資產週轉率為2次，而銷貨收入為$2,000,000。X1年平均權益$800,000， 其中$100,000是股利率10% 的特別股（X1年股利已宣告並支付），平均負債之利率為10%，所 得稅率20%，平均總資產報酬率20%，則平均普通股權益報酬率為何？', '["24.85%", "26.28%", "23%", "21.75%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00597', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司採用曆年制，甲公司於X2年底發現X1年底之期末存貨低估$10,000，X1年之折舊費用 高估$20,000，X2年底之應收帳款低估$20,000。在尚未調整上述X1年及X2年之錯誤前，甲公 司X2年底的流動比率為2，營運資金為$360,000。試問甲公司X2年底正確的流動資產為何？', '["$720,000", "$730,000", "$740,000", "$750,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00598', 'cpa', 'cpa-moex-109-78566e18', 'sub-cpa-01', NULL, 'single_choice', '有關使用權資產原始衡量之敘述，下列何者正確？', '["租賃開始時，承租人認列之使用權資產之金額會等於所認列租賃負債之金額", "承租人認列使用權資產之金額應包括出租人支付給仲介的佣金", "承租人認列使用權資產之金額應扣除出租人同意歸墊之仲介佣金", "承租人認列使用權資產之金額不應包括復原標的資產所在地點至租賃條件所要求狀態之估 計成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:07+00:00", "source_pdf_sha1": "25b6ba044ccf", "answer_pdf_sha1": "c2d4cf1a4ab0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
